impl SseEncode for crate::api::FrbBenchEvent {
    // Codec=Sse (Serialization based), see doc to use other codecs
    fn sse_encode(self, serializer: &mut flutter_rust_bridge::for_generated::SseSerializer) {
        match self {
            crate::api::FrbBenchEvent::StateChanged { from, to } => {
                <i32>::sse_encode(0, serializer);
                <String>::sse_encode(from, serializer);
                <String>::sse_encode(to, serializer);
            }
            crate::api::FrbBenchEvent::Sample(field0) => {
                <i32>::sse_encode(1, serializer);
                <crate::api::FrbResourceSample>::sse_encode(field0, serializer);
            }
            crate::api::FrbBenchEvent::Token { index, text } => {
                <i32>::sse_encode(2, serializer);
                <u32>::sse_encode(index, serializer);
                <String>::sse_encode(text, serializer);
            }
            crate::api::FrbBenchEvent::WatchdogWarn => {
                <i32>::sse_encode(3, serializer);
            }
            crate::api::FrbBenchEvent::WatchdogKill => {
                <i32>::sse_encode(4, serializer);
            }
            crate::api::FrbBenchEvent::RunFinished {
                run_id,
                status,
                result,
            } => {
                <i32>::sse_encode(5, serializer);
                <u64>::sse_encode(run_id, serializer);
                <String>::sse_encode(status, serializer);
                <Option<crate::api::FrbBenchResult>>::sse_encode(result, serializer);
            }
            crate::api::FrbBenchEvent::Log { level, message } => {
                <i32>::sse_encode(6, serializer);
                <String>::sse_encode(level, serializer);
                <String>::sse_encode(message, serializer);
            }
            crate::api::FrbBenchEvent::Progress { message } => {
                <i32>::sse_encode(7, serializer);
                <String>::sse_encode(message, serializer);
            }
            _ => {
                unimplemented!("");
            }
        }
    }
}

